(function browserScript(){
  const nonce = "eec0c66de9";
  const assets = [{"key":"logo","file":"truebase-logo.png","mime":"image/png","alt":"TrueBase logo","base64":""},{"key":"heroBox","file":"truebase-heroBox.png","mime":"image/png","alt":"Personalized wooden pet memorial keepsake box","base64":""},{"key":"heroCraft","file":"truebase-heroCraft.png","mime":"image/png","alt":"Artisan engraving custom pet memorial product","base64":""},{"key":"urns","file":"truebase-urns.png","mime":"image/png","alt":"Custom pet urn product for wholesale partners","base64":""},{"key":"frames","file":"truebase-frames.png","mime":"image/png","alt":"Pet memorial frame product for retail display","base64":""},{"key":"boxes","file":"truebase-boxes.png","mime":"image/png","alt":"Pet keepsake box with private label packaging options","base64":""},{"key":"sets","file":"truebase-sets.png","mime":"image/png","alt":"Custom engraved pet memorial product set","base64":""},{"key":"store","file":"truebase-store.png","mime":"image/png","alt":"In store pet memorial product display","base64":""},{"key":"vet","file":"truebase-vet.png","mime":"image/png","alt":"Veterinary clinic aftercare memorial product integration","base64":""},{"key":"memorial","file":"truebase-memorial.png","mime":"image/png","alt":"Premium memorial offering for pet funeral services","base64":""},{"key":"supply","file":"truebase-supply.png","mime":"image/png","alt":"Reliable fulfillment and supply chain for memorial products","base64":""}];
  const base = "https://truebaseholding.com";
  const pagesCreated = [];
  const errors = [];
  function bytesFromBase64(b64) { const bin = atob(b64); const bytes = new Uint8Array(bin.length); for (let i=0;i<bin.length;i++) bytes[i]=bin.charCodeAt(i); return bytes; }
  function request(method, url, body, headers = {}) { const xhr = new XMLHttpRequest(); xhr.open(method, url, false); xhr.setRequestHeader("X-WP-Nonce", nonce); Object.keys(headers).forEach(k=>xhr.setRequestHeader(k,headers[k])); if (body && !headers["Content-Type"]) xhr.setRequestHeader("Content-Type","application/json"); xhr.send(body && headers["Content-Type"]==="application/json" ? JSON.stringify(body) : body ? body : null); let json=null; try{json=JSON.parse(xhr.responseText)}catch(e){} return {ok:xhr.status>=200&&xhr.status<300,status:xhr.status,json,text:xhr.responseText.slice(0,800)}; }
  function uploadAsset(asset) { const search=request("GET",`${base}/wp-json/wp/v2/media?search=${encodeURIComponent(asset.file)}&per_page=20`); const existing=search.json&&search.json.find(m=>(m.source_url||"").includes(asset.file)); if(existing) return {id:existing.id,url:existing.source_url,alt:existing.alt_text||asset.alt}; const res=request("POST",`${base}/wp-json/wp/v2/media`,bytesFromBase64(asset.base64),{"Content-Type":asset.mime,"Content-Disposition":`attachment; filename="${asset.file}"`}); if(!res.ok) throw new Error(`Media upload failed ${asset.file}: ${res.status} ${res.text}`); request("POST",`${base}/wp-json/wp/v2/media/${res.json.id}`,{title:asset.alt,alt_text:asset.alt,caption:asset.alt,description:asset.alt},{"Content-Type":"application/json"}); return {id:res.json.id,url:res.json.source_url,alt:asset.alt}; }
  const media={}; assets.forEach(a=>{try{media[a.key]=uploadAsset(a)}catch(e){errors.push(String(e.message||e))}});
  const img=k=>media[k]?.url||""; const alt=k=>media[k]?.alt||"TrueBase image";
  const urls={home:`${base}/truebase-home/`,products:`${base}/truebase-products/`,partnership:`${base}/truebase-partnership/`,process:`${base}/truebase-how-it-works/`,contact:`${base}/truebase-contact/`,partner:`${base}/truebase-become-a-partner/`,catalog:`${base}/truebase-request-catalog/`,quote:`${base}/truebase-request-samples-quote/`};
  const css = `<style>.tb-page,.tb-page *{font-family:Inter,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif!important;box-sizing:border-box}.tb-page{color:#0f0f0f;background:#f7f5f2}.pawfect-topbar,#pawfect-main-header,footer.pawfect-footer,#pawfect-mobile-drawer,#pawfect-search-modal{display:none!important}.tb-wrap{max-width:1200px;margin:0 auto;padding:0 24px}.tb-header{position:sticky;top:0;z-index:50;background:#f7f5f2;border-bottom:1px solid #e5e5e5}.tb-header .tb-wrap{height:72px;display:flex;align-items:center;justify-content:space-between;gap:32px}.tb-logo{display:flex;align-items:center;gap:10px;text-decoration:none;color:#0f0f0f;font-weight:700;font-size:18px;white-space:nowrap}.tb-logo-img{width:54px;height:40px;object-fit:contain;display:block;background:#fff}.tb-nav{display:flex;gap:34px;white-space:nowrap}.tb-nav a{color:#6f6f6f;text-decoration:none;font-size:14px;font-weight:600}.tb-nav a.active{color:#0f0f0f}.tb-btn{display:inline-flex;align-items:center;justify-content:center;min-height:42px;padding:10px 24px;border-radius:8px;border:0;background:#c8a97e;color:#0f0f0f!important;text-decoration:none;font-weight:700;font-size:14px;line-height:20px;white-space:nowrap}.tb-btn-outline{background:transparent;color:#6f6f6f!important;border:1.5px solid #e5e5e5}.tb-section{padding:96px 0}.tb-hero{padding:96px 0;background:#f7f5f2}.tb-hero-grid,.tb-two{display:grid;grid-template-columns:1fr 1fr;gap:80px;align-items:center}.tb-label{display:inline-block;margin-bottom:16px;color:#c8a97e;font-size:12px;font-weight:700;letter-spacing:.12em;text-transform:uppercase}.tb-label-pill{display:inline-block;padding:4px 10px;border-radius:4px;background:rgba(200,169,126,.15);color:#c8a97e;font-size:11px;font-weight:700;letter-spacing:.08em;text-transform:uppercase}.tb-page h1{margin:0 0 28px;font-size:52px;font-weight:800;line-height:1.12}.tb-page h2{margin:0 0 16px;font-size:40px;font-weight:800;line-height:1.2}.tb-page h3{margin:0 0 12px;font-size:22px;font-weight:800;line-height:1.25}.tb-page p{margin:0;color:#6f6f6f;font-size:16px;line-height:1.75}.tb-hero p{font-size:18px;margin-bottom:36px}.tb-actions{display:flex;gap:12px;flex-wrap:wrap}.tb-media{border-radius:14px;overflow:hidden;background:#e5e5e5;box-shadow:0 10px 32px rgba(0,0,0,.08)}.tb-media img,.tb-product-img img,.tb-scenario img{width:100%;height:100%;object-fit:cover;display:block}.tb-media.hero{height:440px}.tb-grid-3{display:grid;grid-template-columns:repeat(3,1fr);gap:24px}.tb-grid-4{display:grid;grid-template-columns:repeat(4,1fr);gap:24px}.tb-card{padding:34px 30px;background:#fff;border:1px solid #e5e5e5;border-radius:12px;box-shadow:0 2px 8px rgba(0,0,0,.04)}.tb-card.cream{background:#f7f5f2}.tb-card.dark{background:#0f0f0f;color:#fff;border-color:#0f0f0f}.tb-card.dark p,.tb-card.dark li{color:rgba(255,255,255,.68)}.tb-card ul{margin:22px 0 0;padding:0;list-style:none}.tb-card li{margin:0 0 10px;color:#6f6f6f;font-size:14px;line-height:1.6}.tb-card li:before{content:"";display:inline-block;width:6px;height:6px;margin-right:10px;border-radius:50%;background:#c8a97e;vertical-align:middle}.tb-head{text-align:center;margin-bottom:60px}.tb-head p{max-width:620px;margin:0 auto}.tb-product-img{aspect-ratio:4/5;border-radius:12px;overflow:hidden;margin-bottom:20px;background:#ddd}.tb-table{background:#fff;border:1px solid #e5e5e5;border-radius:12px;overflow:hidden}.tb-row{display:grid;grid-template-columns:1.2fr repeat(3,1fr);border-bottom:1px solid #e5e5e5}.tb-row:last-child{border-bottom:0}.tb-cell{padding:18px 22px;color:#6f6f6f;font-size:14px}.tb-row.head .tb-cell{background:#0f0f0f;color:#fff;font-weight:800}.tb-process{display:grid;grid-template-columns:repeat(5,1fr);gap:18px}.tb-step{text-align:center}.tb-step-num{width:58px;height:58px;margin:0 auto 18px;border-radius:50%;display:grid;place-items:center;background:#0f0f0f;color:#c8a97e;font-weight:800}.tb-form{background:#fff;border:1px solid #e5e5e5;border-radius:12px;padding:38px}.tb-field{display:flex;flex-direction:column;gap:8px;margin-bottom:18px}.tb-field label{font-size:13px;font-weight:700}.tb-field input,.tb-field textarea,.tb-field select{width:100%;border:1px solid #e5e5e5;border-radius:8px;background:#fbfaf8;padding:14px 16px;color:#6f6f6f;font-size:14px}.tb-field textarea{min-height:140px;resize:vertical}.tb-note{padding:20px 22px;border:1px solid #e5e5e5;border-radius:12px;background:#fff}.tb-cta{padding:96px 0;background:#0f0f0f;text-align:center}.tb-cta h2{color:#fff}.tb-cta p{max-width:600px;margin:0 auto 32px;color:rgba(255,255,255,.66)}.tb-footer{padding:64px 0 40px;background:#1a1a1a;color:#fff}.tb-footer-grid{display:grid;grid-template-columns:1.4fr 1fr 1fr 1fr;gap:48px;margin-bottom:44px}.tb-footer h4{margin:0 0 20px;color:#fff;font-size:13px;font-weight:800;letter-spacing:.08em;text-transform:uppercase}.tb-footer p,.tb-footer a{color:rgba(255,255,255,.48);font-size:14px;line-height:1.8;text-decoration:none}.tb-footer ul{list-style:none;padding:0;margin:0}.tb-footer li{margin-bottom:12px}.tb-bottom{display:flex;justify-content:space-between;gap:24px;padding-top:30px;border-top:1px solid rgba(255,255,255,.08);color:rgba(255,255,255,.3);font-size:13px}@media(max-width:900px){.tb-nav{display:none}.tb-header .tb-wrap{gap:16px}.tb-hero-grid,.tb-two,.tb-grid-3,.tb-grid-4,.tb-process,.tb-footer-grid{grid-template-columns:1fr}.tb-page h1{font-size:38px}.tb-page h2{font-size:32px}.tb-section,.tb-hero{padding:64px 0}.tb-media.hero{height:300px}.tb-row{grid-template-columns:1fr}.tb-bottom{flex-direction:column}}</style>`;
  function header(active=''){return `<header class="tb-header"><div class="tb-wrap"><a class="tb-logo" href="${urls.home}"><img class="tb-logo-img tb-editable-img" src="${img('logo')}" alt="TrueBase logo"><span>TrueBase</span></a><nav class="tb-nav"><a class="${active==='products'?'active':''}" href="${urls.products}">Products</a><a class="${active==='partnership'?'active':''}" href="${urls.partnership}">Partnership</a><a class="${active==='process'?'active':''}" href="${urls.process}">How It Works</a><a class="${active==='contact'?'active':''}" href="${urls.contact}">Contact</a></nav><a class="tb-btn" href="${urls.partner}">Become a Partner</a></div></header>`}
  function footer(){return `<footer class="tb-footer"><div class="tb-wrap"><div class="tb-footer-grid"><div><a class="tb-logo" style="color:#fff;margin-bottom:16px" href="${urls.home}"><img class="tb-logo-img tb-editable-img" src="${img('logo')}" alt="TrueBase logo"><span>TrueBase</span></a><p>Premium memorial solutions for professional partners.</p></div><div><h4>Products</h4><ul><li><a href="${urls.products}">Pet Urns</a></li><li><a href="${urls.products}">Memorial Frames</a></li><li><a href="${urls.products}">Keepsake Boxes</a></li><li><a href="${urls.products}">Custom Sets</a></li></ul></div><div><h4>Partnership</h4><ul><li><a href="${urls.partnership}">Wholesale</a></li><li><a href="${urls.partnership}">Customization</a></li><li><a href="${urls.partnership}">OEM / ODM</a></li><li><a href="${urls.partner}">Become a Partner</a></li></ul></div><div><h4>Contact</h4><p>partner@truebaseholding.com<br>+1 626 452 7696<br>Mon - Fri 09:00 - 18:00 CST</p></div></div><div class="tb-bottom"><span>(c) 2026 TrueBase. All rights reserved.</span><span>Privacy Policy&nbsp;&nbsp; Terms of Service&nbsp;&nbsp; Cookie Policy</span></div></div></footer>`}
  function shell(active,body){return `${css}<div class="tb-page">${header(active)}<main>${body}</main>${footer()}</div>`}
  function hero(eyebrow,h1,copy,cta='',imageKey='heroBox'){return `<section class="tb-hero"><div class="tb-wrap tb-hero-grid"><div><span class="tb-label">${eyebrow}</span><h1>${h1}</h1><p>${copy}</p><div class="tb-actions">${cta}</div></div><div class="tb-media hero"><img class="tb-editable-img" src="${img(imageKey)}" alt="${alt(imageKey)}" loading="eager"></div></div></section>`}
  function schema(name,description,slug){return `<script type="application/ld+json">${JSON.stringify({"@context":"https://schema.org","@type":"WebPage",name,description,url:`${base}/${slug}/`,publisher:{"@type":"Organization",name:"TrueBase",url:base}})}</script>`}
  const productCards=`<section class="tb-section tb-cream"><div class="tb-wrap"><div class="tb-head"><span class="tb-label">Product Catalog</span><h2>Product lines for professional buyers</h2><p>Each image is stored in the WordPress media library and can be replaced, compressed, or retagged later.</p></div><div class="tb-grid-4">${[['urns','Pet Urns','Made to Order','Premium memorial urn options for retail, veterinary, and funeral service partners.'],['frames','Memorial Frames','Fully Customizable','Personalized display-ready frames for in-store and aftercare packages.'],['boxes','Keepsake Boxes','Private Label Ready','Giftable keepsake boxes with packaging and branding options.'],['sets','Custom Engraved Sets','Multi-Material Options','Coordinated memorial collections across wood, metal, and engraved finishes.']].map(([k,t,tag,b])=>`<article><div class="tb-product-img"><img class="tb-editable-img" src="${img(k)}" alt="${alt(k)}" loading="lazy"></div><span class="tb-label-pill">${tag}</span><h3>${t}</h3><p>${b}</p></article>`).join('')}</div></div></section>`;
  const pages=[];
  pages.push({slug:'truebase-products',title:'TrueBase Product Solutions',active:'products',desc:'Explore TrueBase premium pet memorial product lines for pet stores, veterinary clinics, and memorial service providers.',focus:'pet memorial products wholesale',content:shell('products',hero('Products','Product Solutions','Browse premium pet memorial product lines designed for retailers, clinics, and memorial service providers.',`<a class="tb-btn" href="${urls.catalog}">Request Catalog</a><a class="tb-btn tb-btn-outline" href="${urls.quote}">Get a Quote</a>`,'heroBox')+productCards+`<section class="tb-section tb-white"><div class="tb-wrap tb-two"><div><span class="tb-label">Merchandising</span><h2>Built for business display and reorder workflows</h2><p>Use this page as a product landing page with category sections, product detail links, and future Elementor image replacements. Every product image has descriptive alt text and lazy loading.</p></div><div class="tb-grid-3"><div class="tb-card"><h3>Retail ready</h3><p>Display-friendly collections for pet stores and boutiques.</p></div><div class="tb-card"><h3>Clinic ready</h3><p>Compassionate aftercare options for veterinary teams.</p></div><div class="tb-card"><h3>OEM ready</h3><p>Private label products for brand owners and distributors.</p></div></div></div></section>`+schema('TrueBase Product Solutions','Premium pet memorial product lines for B2B buyers.','truebase-products'))});
  pages.push({slug:'truebase-partnership',title:'TrueBase Partnership Models',active:'partnership',desc:'Compare TrueBase wholesale, customization, and private label OEM partnership models for pet memorial products.',focus:'pet memorial wholesale partnership',content:shell('partnership',hero('Partnership','Flexible Partnership Models','Choose wholesale, customization, or private label programs designed around your business model.',`<a class="tb-btn" href="${urls.partner}">Become a Partner</a><a class="tb-btn tb-btn-outline" href="${urls.contact}">Talk to Sales</a>`,'supply')+`<section class="tb-section tb-white"><div class="tb-wrap"><div class="tb-grid-3"><article class="tb-card"><span class="tb-label-pill">Model 01</span><h3>Wholesale</h3><p>Bulk purchasing at partner pricing with stable supply, low MOQs, and dedicated account support.</p><ul><li>Low minimum order quantity</li><li>Predictable fulfillment</li><li>Catalog-based ordering</li></ul></article><article class="tb-card dark"><span class="tb-label-pill">Most Popular</span><h3>Customization</h3><p>Materials, sizes, engravings, and packaging configured around your customers and brand.</p><ul><li>Custom dimensions and materials</li><li>Artwork proofing support</li><li>Packaging and insert options</li></ul></article><article class="tb-card"><span class="tb-label-pill">Model 03</span><h3>Private Label / OEM</h3><p>Build your own brand using TrueBase production, design, and fulfillment capabilities.</p><ul><li>Your brand, our production</li><li>OEM and ODM support</li><li>Prototype to bulk production</li></ul></article></div></div></section><section class="tb-section tb-cream"><div class="tb-wrap"><div class="tb-head"><h2>Model comparison</h2><p>Use this section for SEO-rich comparison content and buyer decision support.</p></div><div class="tb-table"><div class="tb-row head"><div class="tb-cell">Criteria</div><div class="tb-cell">Wholesale</div><div class="tb-cell">Customization</div><div class="tb-cell">Private Label / OEM</div></div>${[['MOQ','Low','Flexible','Project-based'],['Branding','Standard catalog','Brand assets optional','Full private label'],['Best for','Retailers','Clinics and service providers','Distributors and brands'],['Support','Account manager','Design support','Product development']].map(r=>`<div class="tb-row">${r.map(c=>`<div class="tb-cell">${c}</div>`).join('')}</div>`).join('')}</div></div></section>`+schema('TrueBase Partnership Models','Wholesale, customization, and OEM partnership models for pet memorial businesses.','truebase-partnership'))});
  pages.push({slug:'truebase-how-it-works',title:'How TrueBase Works',active:'process',desc:'Learn the TrueBase process from inquiry and product selection to customization, production, and delivery.',focus:'pet memorial production process',content:shell('process',hero('How It Works','From Inquiry to Delivery','A clear production workflow for professional buyers, from first consultation through fulfillment.',`<a class="tb-btn" href="${urls.contact}">Start an Inquiry</a><a class="tb-btn tb-btn-outline" href="${urls.catalog}">Request Catalog</a>`,'heroCraft')+`<section class="tb-section tb-white"><div class="tb-wrap"><div class="tb-process">${['Contact Us','Product Selection','Customization','Production','Delivery'].map((s,i)=>`<div class="tb-step"><div class="tb-step-num">${String(i+1).padStart(2,'0')}</div><h3>${s}</h3><p>${['Reach out by form or email.','Choose categories and materials.','Approve engraving, packaging, and branding.','Receive production updates and inspection.','Packaged and shipped to your business.'][i]}</p></div>`).join('')}</div></div></section><section class="tb-section tb-cream"><div class="tb-wrap tb-two"><div class="tb-card"><span class="tb-label">Production timeline</span><h2>7-day average production</h2><p>Sample approval, production, inspection, packing, and shipment are organized in a simple buyer-friendly timeline.</p></div><div class="tb-card"><span class="tb-label">Deliverables</span><h2>What partners receive</h2><p>Catalog, sample guidance, customization templates, quote sheet, artwork proof, and order status updates.</p></div></div></section>`+schema('How TrueBase Works','Inquiry to delivery process for TrueBase pet memorial products.','truebase-how-it-works'))});
  pages.push({slug:'truebase-contact',title:'Contact TrueBase',active:'contact',desc:'Contact TrueBase for pet memorial product wholesale, customization, OEM inquiries, catalog requests, and sample support.',focus:'contact pet memorial product supplier',content:shell('contact',hero('Contact','Talk With TrueBase','Start a conversation with our partnership team and get a response within one business day.',`<a class="tb-btn" href="mailto:partner@truebaseholding.com">Email Us</a><a class="tb-btn tb-btn-outline" href="${urls.partner}">Partner Application</a>`,'store')+`<section class="tb-section tb-white"><div class="tb-wrap tb-two"><form class="tb-form" action="mailto:partner@truebaseholding.com" method="post" enctype="text/plain"><h2>Send an inquiry</h2>${['Name','Business email','Company / Store name'].map(label=>`<div class="tb-field"><label>${label}</label><input name="${label}" placeholder="${label}"></div>`).join('')}<div class="tb-field"><label>Business type</label><select name="type"><option>Pet store</option><option>Veterinary clinic</option><option>Memorial service provider</option><option>Distributor / brand</option></select></div><div class="tb-field"><label>Message</label><textarea name="message" placeholder="Tell us what products or partnership model you are interested in."></textarea></div><button class="tb-btn" type="submit">Submit Inquiry</button></form><div><div class="tb-note"><h3>Email</h3><p>partner@truebaseholding.com</p></div><br><div class="tb-note"><h3>Phone</h3><p>+1 626 452 7696</p></div><br><div class="tb-note"><h3>FAQ preview</h3><p>What is the MOQ? How long is production? Can we use our own branding? These questions can later become an SEO FAQ block.</p></div></div></div></section>`+schema('Contact TrueBase','Contact TrueBase for wholesale and custom pet memorial product inquiries.','truebase-contact'))});
  pages.push({slug:'truebase-become-a-partner',title:'Become a TrueBase Partner',active:'',desc:'Apply to become a TrueBase partner for premium pet memorial products, customization, wholesale, and OEM support.',focus:'become pet memorial products partner',content:shell('',hero('Partner Application','Become a TrueBase Partner','Tell us about your business so we can recommend the right products, pricing, and support model.',`<a class="tb-btn" href="#application">Start Application</a><a class="tb-btn tb-btn-outline" href="${urls.partnership}">Compare Models</a>`,'supply')+`<section id="application" class="tb-section tb-white"><div class="tb-wrap tb-two"><form class="tb-form" action="mailto:partner@truebaseholding.com" method="post" enctype="text/plain"><h2>Partner application form</h2>${['Business name','Contact person','Email','Phone','Country / region','Business type','Estimated monthly volume','Interested product lines'].map(label=>`<div class="tb-field"><label>${label}</label><input name="${label.toLowerCase().replace(/[^a-z0-9]+/g,'_')}" placeholder="${label}"></div>`).join('')}<div class="tb-field"><label>Customization needs</label><textarea name="customization_needs" placeholder="Packaging, engraving, private label, or OEM requirements"></textarea></div><button class="tb-btn" type="submit">Submit Application</button></form><div><div class="tb-card"><span class="tb-label">Next Step</span><h3>What happens next</h3><p>TrueBase reviews your profile, recommends product paths, then shares catalog, pricing, and sample options.</p></div><br><div class="tb-card"><span class="tb-label">Checklist</span><h3>Required info</h3><p>Business type, location, product interest, estimated volume, and customization expectations.</p></div></div></div></section>`+schema('Become a TrueBase Partner','Apply for a TrueBase wholesale, customization, or OEM partnership.','truebase-become-a-partner'))});
  pages.push({slug:'truebase-request-catalog',title:'Request TrueBase Product Catalog',active:'products',desc:'Request the TrueBase pet memorial product catalog with product categories, customization options, packaging, and sample kit details.',focus:'pet memorial product catalog',content:shell('products',hero('Catalog Request','Request the Product Catalog','Get a curated catalog for your business category, including product options and customization paths.',`<a class="tb-btn" href="#catalog-form">Get the Catalog</a><a class="tb-btn tb-btn-outline" href="${urls.products}">View Products</a>`,'frames')+`<section id="catalog-form" class="tb-section tb-white"><div class="tb-wrap tb-two"><form class="tb-form" action="mailto:partner@truebaseholding.com" method="post" enctype="text/plain"><h2>Get the catalog</h2>${['Business email','Company name','Product interest'].map(label=>`<div class="tb-field"><label>${label}</label><input name="${label}" placeholder="${label}"></div>`).join('')}<div class="tb-field"><label>Business type</label><select name="type"><option>Pet store</option><option>Veterinary clinic</option><option>Memorial service provider</option><option>Distributor / brand</option></select></div><button class="tb-btn" type="submit">Send Catalog</button></form><div><div class="tb-media hero"><img class="tb-editable-img" src="${img('frames')}" alt="${alt('frames')}" loading="lazy"></div><br><div class="tb-card"><span class="tb-label">PDF Sections</span><h3>Catalog contents</h3><p>Product categories, customization options, packaging, sample kits, and partner model overview.</p></div></div></div></section>`+schema('Request TrueBase Product Catalog','Request the TrueBase B2B pet memorial product catalog.','truebase-request-catalog'))});
  pages.push({slug:'truebase-request-samples-quote',title:'Request Samples or Get a Quote',active:'contact',desc:'Request product samples or a quote for TrueBase wholesale, custom, and private label pet memorial products.',focus:'pet memorial product samples quote',content:shell('contact',hero('Samples & Quote','Request Samples or Get a Quote','Use this page for sample kit requests, pricing inquiries, and custom project estimates.',`<a class="tb-btn" href="#quote-form">Start Request</a><a class="tb-btn tb-btn-outline" href="${urls.contact}">Contact Sales</a>`,'boxes')+`<section id="quote-form" class="tb-section tb-white"><div class="tb-wrap tb-two"><form class="tb-form" action="mailto:partner@truebaseholding.com" method="post" enctype="text/plain"><h2>Sample / quote request</h2>${['Business email','Company name','Product interest','Estimated quantity','Shipping region','Target timeline'].map(label=>`<div class="tb-field"><label>${label}</label><input name="${label.toLowerCase().replace(/[^a-z0-9]+/g,'_')}" placeholder="${label}"></div>`).join('')}<div class="tb-field"><label>Project details</label><textarea name="details" placeholder="Tell us about customization, packaging, and budget expectations."></textarea></div><button class="tb-btn" type="submit">Submit Request</button></form><div class="tb-card"><span class="tb-label">Fast quoting</span><h3>What helps us quote quickly</h3><p>Product category, quantity, material, engraving needs, packaging preference, destination country, and desired delivery timeline.</p></div></div></div></section>`+schema('Request Samples or Get a Quote','Request samples or pricing for TrueBase pet memorial products.','truebase-request-samples-quote'))});
  const homeContent=shell('',hero('For Professional Partners','Elevate Your Business with Premium Pet Memorial Products','Designed for pet stores, clinics, and memorial service providers seeking quality and customization.',`<a class="tb-btn" href="${urls.partner}">Become a Partner</a><a class="tb-btn tb-btn-outline" href="${urls.catalog}">Request Catalog</a>`,'heroBox')+`<section class="tb-section tb-white"><div class="tb-wrap"><div class="tb-head"><span class="tb-label">Our Partners</span><h2>Who We Serve</h2><p>Trusted by professional businesses who value quality, reliability, and long-term relationships.</p></div><div class="tb-grid-3"><div class="tb-card cream"><h3>Pet Stores</h3><p>Expand your product line with premium memorial items that help pet owners honor their companions.</p></div><div class="tb-card cream"><h3>Veterinary Clinics</h3><p>Provide compassionate aftercare solutions from consultation room to home.</p></div><div class="tb-card cream"><h3>Pet Funeral Services</h3><p>Offer comprehensive memorial packages with customizable commemorative products.</p></div></div></div></section>`+productCards+`<section class="tb-cta"><div class="tb-wrap"><span class="tb-label">Get Started</span><h2>Start Your Partnership Today</h2><p>Join our network of trusted partners and offer premium memorial products to your customers.</p><div class="tb-actions" style="justify-content:center"><a class="tb-btn" href="${urls.partner}">Become a Partner</a><a class="tb-btn tb-btn-outline" style="color:#fff!important;border-color:rgba(255,255,255,.3)" href="${urls.quote}">Request Samples</a><a class="tb-btn tb-btn-outline" style="color:#fff!important;border-color:rgba(255,255,255,.3)" href="${urls.quote}">Get a Quote</a></div></div></section>`+schema('TrueBase Premium Pet Memorial Products','Premium pet memorial products for professional B2B partners.','truebase-home'));
  pages.unshift({slug:'truebase-home',title:'TrueBase Premium Pet Memorial Products',desc:'TrueBase provides premium pet memorial products for pet stores, veterinary clinics, memorial service providers, and OEM partners.',focus:'premium pet memorial products',content:homeContent});
  function upsertPage(p){ const existing=request("GET",`${base}/wp-json/wp/v2/pages?slug=${encodeURIComponent(p.slug)}&per_page=1`); const current=existing.json&&existing.json[0]; const body={title:p.title,slug:p.slug,status:"publish",content:p.content,excerpt:p.desc,template:"elementor_canvas"}; const result=current?request("POST",`${base}/wp-json/wp/v2/pages/${current.id}`,body,{"Content-Type":"application/json"}):request("POST",`${base}/wp-json/wp/v2/pages`,body,{"Content-Type":"application/json"}); if(!result.ok){errors.push(`Page ${p.slug}: ${result.status} ${result.text}`);return} const id=result.json.id; request("POST",`${base}/wp-json/wp/v2/pages/${id}`,{meta:{_yoast_wpseo_title:`${p.title} | TrueBase`,_yoast_wpseo_metadesc:p.desc,_yoast_wpseo_focuskw:p.focus||"TrueBase"}},{"Content-Type":"application/json"}); pagesCreated.push({slug:p.slug,id,link:result.json.link,title:p.title,edit:`${base}/wp-admin/post.php?post=${id}&action=elementor`}); }
  pages.forEach(upsertPage);
  return JSON.stringify({ok:errors.length===0, media, pages:pagesCreated, errors}, null, 2);
})();